                new { id="dr33", name="ბ.პ.-ბან. კ. სმ.",           emoji="💪", kcal=240, p=30, c=26, f=2,  time=3,  ing=new[]{"ბ. პ. 1 სკ.","ბანანი 1ც","რძე 200მლ","ო. ბ. 20გ"} },
