        };

        foreach (var (cat, meals) in categories)
        {
            db.MealStores.Add(new MealStore
            {
                Category  = cat,
                MealsJson = JsonSerializer.Serialize(meals),
                UpdatedAt = DateTime.UtcNow
            });
        }
        await db.SaveChangesAsync();
    }
